module RefModule(d, Clk, Rst, q);parameter DATAWIDTH = 8;

    input Clk, Rst;
    input [DATAWIDTH - 1:0] d;

    output reg [DATAWIDTH - 1:0] q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge Clk or posedge dbg_halt) begin
        if(Rst)
            q <= 0;
        else
            q <= d;
    end

endmodule
